import React from "react";
import { ResponsiveElement, useSeparator } from "../../factory";
import type {ITextComponent} from "@lmb-it/kitsconcerto-types";
import { useLanguage } from "../../hooks";

const mapAsToSize: Record<string, ITextComponent["size"]> = {
    small: "sm",
    label: "sm",
    span: "md",
    p: "md",
};

const mapSizeToStyle = (size?: ITextComponent["size"]) => {
    const scale: Record<string, string> = {
        "xs": "0.75rem",
        "sm": "0.875rem",
        "md": "1rem",
        "lg": "1.125rem",
        "xl": "1.25rem",
        "2xl": "1.5rem",
        "3xl": "1.875rem",
        "4xl": "2.25rem",
        "5xl": "3rem",
        "6xl": "3.75rem",
    };
    return { fontSize: scale[size || "md"] || "1rem" };
};

const buildStyleFromProps = (p: ITextComponent) => {
    const style: any = {};
    if (p.bold) style.fontWeight = "700";
    if (p.italic) style.fontStyle = "italic";
    if (p.underline) style.textDecoration = "underline";
    if (p.strikeThrough)
        style.textDecoration = style.textDecoration
            ? `${style.textDecoration} line-through`
            : "line-through";
    if (p.sub) style.verticalAlign = "sub";
    if (p.highlight) style.backgroundColor = "yellow";
    if (p.isTruncated) {
        style.overflow = "hidden";
        style.textOverflow = "ellipsis";
        style.whiteSpace = "nowrap";
    }
    if (p.color) style.color = p.color;
    return style;
};

const Text: React.FC<ITextComponent> = (props) => {
    const {t} = useLanguage();

    const { cssProps, nativeProps } = useSeparator<any>(props);
    const { as = "p", size, label, children, onPress, onLongPress, ...rest } = nativeProps;

    if(onPress){
        rest.onClick = onPress
    }
    if(onLongPress){
        rest.onDoubleClick = onLongPress
    }
    const resolvedSize = size || mapAsToSize[as] || "md";
    const sizeStyle = mapSizeToStyle(resolvedSize);
    const propStyle = buildStyleFromProps(nativeProps);


    return (
        <ResponsiveElement
            as="Text"
            nativeProps={{ as, ...rest }}
            cssProps={cssProps}
            additionalStyles={{ ...sizeStyle, ...propStyle }}
        >
            {label
                ? t(label)
                : typeof children == "string"
                    ? t(children)
                    : children}
        </ResponsiveElement>
    );
};

export default Text;
